#!/bin/bash
GREEN='\033[0;32m'; YELLOW='\033[1;33m'; NC='\033[0m'
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
FE="$SCRIPT_DIR/Beme-Frontend"
echo ""
echo -e "${YELLOW}Installing clean ChatModal...${NC}"
echo "" | base64 -d > "$FE/src/components/ChatModal.jsx"
echo -e "  ${GREEN}✓${NC} ChatModal.jsx"
PD="$FE/src/pages/ProductDetails.jsx"

if ! grep -q "showChat" "$PD"; then
  sed -i "s/const \[moreProducts,  setMoreProducts\]  = useState(\[\]);/const [moreProducts,  setMoreProducts]  = useState([]);\n  const [showChat,      setShowChat]      = useState(false);/" "$PD"
  echo -e "  ${GREEN}✓${NC} Added showChat state"
fi
awk '
/onClick=\{\(\) => navigate\(`\/messages\?seller=/ {
  gsub(/onClick=\{\(\) => navigate\(`\/messages\?seller=.*`\)\}/, "onClick={() => setShowChat(true)}")
}
{ print }
' "$PD" > "$PD.tmp" && mv "$PD.tmp" "$PD" 
awk '
/{showChat && <ChatModal/ { next }
/pd-seller-actions"/ {
  in_actions = 1
}
in_actions && /^      <\/div>/ {
  print
  print "        {showChat && shop2 && <ChatModal shop={shop2} onClose={() => setShowChat(false)} />}"
  in_actions = 0
  next
}
{ print }
' "$PD" > "$PD.tmp" && mv "$PD.tmp" "$PD" 
echo -e "  ${GREEN}✓${NC} ProductDetails.jsx"
echo ""
echo -e "${GREEN}Done! Deploy: cd Beme-Frontend && git add . && git commit -m \"Clean chat modal\" && git push${NC}"